#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int n;
    scanf("%d", &n);
    int money[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &money[i]);
    }
    qsort(money, n, sizeof(int), compare);
    int taxes = 0;
    for (int i = 0; i < n; i++) {
        if (money[i] > 20) {
            taxes += money[i] - 20;
        }
    }
    printf("%d\n", taxes);
    return 0;
}

