import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] money = new int[n];
        for (int i = 0; i < n; i++) {
            money[i] = scanner.nextInt();
        }
        Arrays.sort(money);
        int taxes = 0;
        for (int i = 0; i < n; i++) {
            if (money[i] > 20) {
                taxes += money[i] - 20;
            }
        }
        System.out.println(taxes);
    }
}

code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let money;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        money = input.split(' ').map(Number);
        money.sort((a, b) => a - b);
        let taxes = 0;
        for (let i = 0; i < n; i++) {
            if (money[i] > 20) {
                taxes += money[i] - 20;
            }
        }
        console.log(taxes);
        rl.close();
    }
});

